<script setup lang="ts">import { computed } from 'vue';import MarkdownIt from 'markdown-it';const props=defineProps<{content:string}>();const md=new MarkdownIt({html:false,linkify:true,breaks:true});const fallback=md.renderer.rules.link_open;md.renderer.rules.link_open=(tokens,idx,options,env,self)=>{tokens[idx].attrSet('target','_blank');tokens[idx].attrSet('rel','noopener noreferrer');return fallback?fallback(tokens,idx,options,env,self):self.renderToken(tokens,idx,options);};const html=computed(()=>md.render(props.content||''));</script>
<template><div class="markdown" v-html="html"></div></template>
